#include <stdio.h>
#define MAX_PROCESSES 10
#define MAX_RESOURCES 5

void constructWaitForGraph(int n, int m, int Allocation[][MAX_RESOURCES], 
                          int Request[][MAX_RESOURCES], int WaitFor[MAX_PROCESSES][MAX_PROCESSES]) {
    // Initialize WaitFor matrix to -1 (no wait)
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            WaitFor[i][j] = -1;
        }
    }

    // For each process, check which resources it needs
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            // If process i is requesting resource j
            if (Request[i][j] > 0) {
                // Find which process holds resource j
                for (int k = 0; k < n; k++) {
                    if (Allocation[k][j] > 0) {
                        // Process i waits for process k
                        WaitFor[i][k] = 1;
                    }
                }
            }
        }
    }
}

int detectCycle(int n, int WaitFor[MAX_PROCESSES][MAX_PROCESSES]) {
    // DFS-based cycle detection
    int visited[MAX_PROCESSES] = {0};
    int recStack[MAX_PROCESSES] = {0};

    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            if (isCyclic(i, visited, recStack, WaitFor, n)) {
                return 1; // Cycle detected - deadlock
            }
        }
    }
    return 0; // No deadlock
}

int isCyclic(int v, int visited[], int recStack[], 
             int WaitFor[MAX_PROCESSES][MAX_PROCESSES], int n) {
    visited[v] = 1;
    recStack[v] = 1;

    for (int u = 0; u < n; u++) {
        if (WaitFor[v][u] != -1) {
            if (!visited[u] && isCyclic(u, visited, recStack, WaitFor, n)) {
                return 1;
            }
            if (recStack[u]) {
                return 1; // Cycle found
            }
        }
    }
    recStack[v] = 0;
    return 0;
}
